// 0. 攔截非文字訊息 (貼圖、圖片、影片等直接忽略不處理)
const messageType = $input.item.json.body.events[0].message.type;
if (messageType !== 'text') {
  return { json: { action: 'ignore' } };
}

// 1. 取得 LINE 傳來的完整訊息與相關資訊 (加上 || "" 作為雙重防呆)
const rawText = $input.item.json.body.events[0].message.text || "";
const source = $input.item.json.body.events[0].source;
const replyToken = $input.item.json.body.events[0].replyToken;

// 2. 取得群組 ID 與原始 ID
const originalId = source.groupId || source.userId;
let groupId = originalId;

// 🌟 獨立名單 A：共用群組名單 (在此名單內的人，資料會統一寫入指定的共用群組 ID)
const SHARED_GROUP_LIST = [
  "U3ad9b0e3dd96791a11583269e657fe1e"
];

// 🌟 獨立名單 B：免召喚 VIP 名單 (在此名單內的人，講話不用打 @貓福喵喵)
const NO_MENTION_VIP_LIST = [
  "U3ad9b0e3dd96791a11583269e657fe1e"
];

// 判斷權限與是否有標記
const isSpecialUser = NO_MENTION_VIP_LIST.includes(originalId);
const hasMention = rawText.includes('@貓福喵喵');

// 💡 轉換機關：只要 groupId 在「共用群組名單」內，就統一轉換
if (SHARED_GROUP_LIST.includes(groupId)) {
  groupId = "Ca0839cc9cf253659e58c1cd8927bb165";
}

// 🚫 第一道防線：如果不是「免召喚 VIP」，也沒有標記機器人，直接判定為 ignore (丟棄不處理)
if (!isSpecialUser && !hasMention) {
  return { json: { action: 'ignore' } };
}

// 3. 移除 "@貓福喵喵" 標記 (如果有標記的話)
let text = rawText.replace('@貓福喵喵', '').trim();

let action = '';
let date = '';
let type = '';
let theme = '';
let time = '';
let replyMessage = '';

// 📌 統一的添加格式提示 (全部加上雙反斜線 \\n)
const formatHint = "📝 【正確行程格式】\\n日期 類型 主題名稱 時間\\n✅ 範例：4/3 密室逃脫 絕命旅舍 12:30\\n\\n💡 提示：\\n- 日期請用「/」分隔 (如 4/3)\\n- 時間請用「:」分隔 (如 12:30)\\n- 中間請用「空格」隔開喔！\\n\\n🗑️ 若要移除行程，請在句尾加上「移除」\\n🔍 若要查詢行程，請輸入「行程」";

// 4. 判斷使用者意圖
if (text.toLowerCase() === 'hi') {
  action = 'error'; 
  replyMessage = `這是你的 ID：\\n${originalId}\\n\\n(可以把這串 ID 複製起來，用來設定共用資料喔喵！🐾)`;

} else if (text.includes('行程')) {
  action = 'query';

} else {
  let isRemove = false;
  if (text.endsWith('移除')) {
    isRemove = true;
    text = text.slice(0, -2).trim(); 
  }

  // 🛠️ 終極防呆：將全形數字、全形冒號/斜線轉成半形，並將全形空白轉為一般空白
  text = text.replace(/[０-９]/g, d => String.fromCharCode(d.charCodeAt(0) - 65248))
             .replace(/：/g, ':')
             .replace(/／/g, '/')
             .replace(/　/g, ' ');

  const parts = text.split(/\s+/);

  // 🤖 意圖猜測雷達：如果字串裡有數字、斜線或冒號，極高機率是他想「輸入行程」
  const looksLikeCommand = text.includes('/') || text.includes(':') || /\d/.test(text);

  // 👉 第二道防線：防呆檢查 (少於 4 個字串代表絕對少打了資訊)
  if (parts.length < 4) {
    if (isSpecialUser && !hasMention && !looksLikeCommand) return { json: { action: 'ignore' } };

    action = 'error';
    replyMessage = `❌ 哎呀，你輸入的內容太短或忘記加「空格」了喵！\\n(系統只讀取到 ${parts.length} 個部分，需要 4 個部分)\\n\\n${formatHint}`;

  } else {
    const dateRegex = /^(0?[1-9]|1[0-2])\/(0?[1-9]|[12][0-9]|3[01])$/;
    const timeRegex = /^([01]?[0-9]|2[0-3]):[0-5][0-9]$/;

    let inputDate = null;
    let inputTime = null;
    let remainingParts = [];

    // ✨✨✨ 升級版：雷達掃描自動提取 ✨✨✨
    // 遍歷所有切出來的字串，自動把日期和時間抽出來，剩下的放進 remainingParts
    for (const part of parts) {
      if (!inputDate && dateRegex.test(part)) {
        inputDate = part;
      } else if (!inputTime && timeRegex.test(part)) {
        inputTime = part;
      } else {
        remainingParts.push(part);
      }
    }

    // 👉 錯誤情況分類分析，給予精準的提示
    if (!inputDate || !inputTime) {
      if (isSpecialUser && !hasMention && !looksLikeCommand) return { json: { action: 'ignore' } };

      action = 'error';

      if (!inputDate && !inputTime) {
        replyMessage = `❌ 格式完全錯囉！\\n沒找到正確的「日期」與「時間」。\\n\\n${formatHint}`;
      } else if (!inputDate) {
        replyMessage = `📅 「日期」格式錯誤囉！\\n是不是忘記用「/」了？\\n\\n${formatHint}`;
      } else {
        replyMessage = `⏰ 「時間」格式錯誤囉！\\n是不是忘記用「:」了？\\n\\n${formatHint}`;
      }

    } else {
      // 格式完全正確，成功攔截！
      action = isRemove ? 'remove' : 'add'; 
      date = inputDate;
      time = inputTime;
      // 剩下的字串，第一個當類型，其餘全部拼起來當主題
      type = remainingParts[0] || ""; 
      theme = remainingParts.slice(1).join(' ') || ""; 

      if (action === 'remove') {
        replyMessage = `🗑️ 已收到移除指令，準備刪除紀錄：\\n${date} ${type} ${theme} ${time}`;
      } else {
        replyMessage = `✅ 已添加紀錄：\\n${date} ${type} ${theme} ${time}`;
      }
    }
  }
}

return {
  json: {
    action, date, type, theme, time, groupId, replyToken, replyMessage, originalText: text
  }
};

// 1. 正確回頭抓取「大腦節點」的原始資料 (找回被洗掉的 date, theme, replyToken)
// 注意：請確保引號裡的名字跟你畫布上的大腦節點完全一樣
const originalData = $('Code in JavaScript').first().json;

// 2. 抓取剛才 Google Sheets 查到的結果
const sheetResults = $input.all();

// 3. 判斷是否有查到「真正的」資料 (檢查裡面有沒有 '日期' 這個欄位)
const hasRealData = sheetResults.length > 0 && sheetResults[0].json["日期"];

if (hasRealData) {
  // 🚨 情況 A：Google Sheets 真的有找到資料！代表「重複了」
  return [{
    json: {
      replyToken: originalData.replyToken,
      replyMessage: `⚠️ 哎呀！${originalData.date} 的「${originalData.theme}」已經在行程表裡了喵！🐾`,
      status: "duplicate" // 給下一個節點的路標
    }
  }];
} else {
  // ✅ 情況 B：Google Sheets 沒找到，是空殼！代表可以新增
  // 使用 JavaScript 的展開語法 (...) 把 originalData 原封不動完美繼承下來
  return [{
    json: {
      ...originalData,
      status: "new_item" // 給下一個節點的路標
    }
  }];
}

// 1. 強行回溯到最源頭的 Webhook 把 Token 抓回來
const webhookData = $('Webhook').first().json;
const replyToken = webhookData.body.events[0].replyToken;

// 2. 回溯到「大腦節點」把解析好的行程細節抓回來
// (注意：確保這裡的名字跟你畫布上的大腦節點完全一樣)
const brainData = $('Code in JavaScript').first().json;

// 3. 重新包裝成 HTTP Request 看得懂的格式
return [{
  json: {
    replyToken: replyToken,
    replyMessage: `✅ 已成功添加新紀錄喵！🐾\\n${brainData.date} ${brainData.theme} ${brainData.time}`
  }
}];

// 1. 正確回頭抓取「大腦節點」的原始資料 (找回被洗掉的 date, theme, replyToken)
// 注意：請確保引號裡的名字跟你畫布上的大腦節點完全一樣
const originalData = $('Code in JavaScript').first().json;

// 2. 抓取剛才 Google Sheets 查到的結果
const sheetResults = $input.all();

// 3. 判斷是否有查到「真正的」資料 (檢查裡面有沒有 '日期' 這個欄位)
const hasRealData = sheetResults.length > 0 && sheetResults[0].json["日期"];

if (hasRealData) {
  // ✅ 情況 A：Google Sheets 有找到資料！代表「可以刪除」
  // 使用展開語法 (...) 繼承 originalData，並額外塞入試算表的 row_number
  return [{
    json: {
      ...originalData,
      row_number: sheetResults[0].json.row_number, // 抓取要刪除的行號，給下一個 Delete 節點用
      status: "delete_item" // 給下一個 IF/Switch 節點的路標
    }
  }];
} else {
  // 🚨 情況 B：Google Sheets 沒找到資料！代表「無東西可刪」
  return [{
    json: {
      replyToken: originalData.replyToken,
      replyMessage: `⚠️ 找不到 ${originalData.date} 的「${originalData.theme}」可以刪除喔！確認一下有沒有打錯喵！🐾`,
      status: "not_found" // 給下一個 IF/Switch 節點的路標
    }
  }];
}

// 1. 強行回溯到最源頭的 Webhook 把 Token 抓回來
const webhookData = $('Webhook').first().json;
const replyToken = webhookData.body.events[0].replyToken;

// 2. 回溯到「大腦節點」把解析好的行程細節抓回來
// (注意：確保這裡的名字跟你畫布上的大腦節點完全一樣)
const brainData = $('Code in JavaScript').first().json;

// 3. 重新包裝成 HTTP Request 看得懂的格式
return [{
  json: {
    replyToken: replyToken,
    replyMessage: `✅ 已成功刪除紀錄喵！🐾\\n${brainData.date} ${brainData.theme} ${brainData.time}`
  }
}];

// 1. 先抓取 Webhook 的 Token
const webhook = $node["Webhook"]; 
const replyToken = webhook.json.body.events[0].replyToken;

// 2. 抓取 Google Sheets 傳進來的所有資料
const items = [...$input.all()];

// 🛠️ 智能補零函式
function padZero(str) {
  if (!str) return "";
  return String(str).replace(/\b(\d)\b/g, '0$1');
}

// 📅 動態產生 Google 日曆連結 (加入客製化備註提醒)
function makeGCalUrl(title, dateStr, timeStr, type, originalDesc) {
  const year = new Date().getFullYear();
  const parts = (dateStr || '').split('/');
  const m = (parts[0] || '01').padStart(2, '0');
  const d = (parts[1] || '01').padStart(2, '0');

  const tParts = (timeStr || '').split(':');
  const h = (tParts[0] || '00').padStart(2, '0');
  const min = (tParts[1] || '00').padStart(2, '0');

  const start = `${year}${m}${d}T${h}${min}00`;

  // 預設行程為 1 小時
  let endH = parseInt(h) + 1;
  let endMin = min;
  if (endH >= 24) { endH = 23; endMin = '59'; } 
  const end = `${year}${m}${d}T${String(endH).padStart(2, '0')}${endMin}00`;

  // 💡 魔法在這裡：根據類型，幫 Google 日曆的「備註欄」預先寫好提醒建議
  let reminderNote = "";
  if (title.includes('密室') || (type || '').includes('遊戲') || (type || '').includes('娛樂')) {
    reminderNote = "🔔 【系統溫馨提示】：這是密室逃脫行程！儲存前請記得在上方手動新增「1天前」與「7天前」的通知鬧鐘喔！\n\n";
  } else {
    reminderNote = "🔔 【系統溫馨提示】：點擊儲存前，記得確認是否有設定「1天前」的通知鬧鐘喔！\n\n";
  }

  // 把我們的提示，跟原本 Google Sheets 裡的備註接在一起
  const finalDesc = reminderNote + (originalDesc || '');

  // 產生網址並套用跳轉原生 App 咒語
  return `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(title)}&dates=${start}/${end}&details=${encodeURIComponent(finalDesc)}&openExternalBrowser=1`;
}

// 🌟 將資料按照「補零後的 日期+時間」進行排序
items.sort((a, b) => {
  const dateA = padZero(a.json.日期);
  const dateB = padZero(b.json.日期);
  const timeA = padZero(a.json.時間);
  const timeB = padZero(b.json.時間);
  return `${dateA} ${timeA}`.localeCompare(`${dateB} ${timeB}`);
});

// ==========================================
// 🎨 開始組裝 Flex Message 內容 (精美升級版)
// ==========================================
const flexRows = [];

if (items.length === 0 || !items[0].json.日期) {
  flexRows.push({
    "type": "text",
    "text": "目前沒有任何行程喔喵！🐾",
    "size": "md",
    "color": "#888888",
    "align": "center"
  });
} else {
  // 過濾掉沒有日期的空資料
  const validItems = items.filter(item => item.json.日期);

  validItems.forEach((item, index) => {
    const data = item.json;
    const displayDate = padZero(data.日期);
    const displayTime = padZero(data.時間);
    const displayType = data.類型 || ""; 
    const displayTitle = data.主題名稱 || ""; 
    const displayDesc = data.備註 || data.Desc || ""; 

    const fullTitle = [displayType, displayTitle].filter(Boolean).join(' ');
    const gcalUrl = makeGCalUrl(fullTitle, data.日期, data.時間, displayType, displayDesc);

    // 每個行程的獨立區塊
    flexRows.push({
      "type": "box",
      "layout": "horizontal",
      "spacing": "md",
      "margin": "md",
      "alignItems": "center",
      "action": {
        "type": "uri",
        "uri": gcalUrl 
      },
      "contents": [
        // 左側：日期與時間 (分層顯示)
        {
          "type": "box",
          "layout": "vertical",
          "flex": 2,
          "contents": [
            { "type": "text", "text": displayDate, "color": "#8c8c8c", "size": "xs", "weight": "bold" },
            { "type": "text", "text": displayTime, "color": "#e74c3c", "size": "sm", "weight": "bold" }
          ]
        },
        // 右側：行程標題 + 新增按鈕
        {
          "type": "box",
          "layout": "horizontal",
          "flex": 5,
          "alignItems": "center",
          "contents": [
            { "type": "text", "text": fullTitle, "weight": "bold", "size": "sm", "color": "#2c3e50", "wrap": true, "flex": 4 },
            { "type": "text", "text": "➕", "size": "xs", "color": "#3498db", "align": "end", "flex": 1 }
          ]
        }
      ]
    });

    // 如果不是最後一個行程，就加一條優雅的分隔線
    if (index < validItems.length - 1) {
      flexRows.push({
        "type": "separator",
        "margin": "md",
        "color": "#f0f0f0"
      });
    }
  });
}

// ==========================================
// 📦 封裝成 LINE Flex 卡片
// ==========================================
const flexMessage = {
  "type": "flex",
  "altText": "📅 您的行程清單已送達！",
  "contents": {
    "type": "bubble",
    "size": "mega",
    // 🖼️ 頂部英雄圖片 (Hero)
    "hero": {
      "type": "image",
      "url": "https://images.unsplash.com/photo-1436491865332-7a61a109cc05?auto=format&fit=crop&w=800&q=80", // 👈 飛機旅行風格圖片，可自行替換
      "size": "full",
      "aspectRatio": "20:10",
      "aspectMode": "cover"
    },
    // 📝 主體內容 (Body)
    "body": {
      "type": "box",
      "layout": "vertical",
      "paddingAll": "20px",
      "contents": [
        {
          "type": "text",
          "text": "✈️ 貓福喵喵行程表",
          "weight": "bold",
          "color": "#3498db",
          "size": "xl",
          "margin": "md"
        },
        {
          "type": "separator",
          "margin": "lg",
          "color": "#e0e0e0"
        },
        {
          "type": "box",
          "layout": "vertical",
          "margin": "md",
          "contents": flexRows
        }
      ]
    },
    // 🔘 底部按鈕 (Footer)
    "footer": {
      "type": "box",
      "layout": "vertical",
      "paddingAll": "15px",
      "contents": [
        {
          "type": "button",
          "style": "secondary",
          "color": "#f0f8ff",
          "action": {
            "type": "uri",
            "label": "查看完整行程與地圖",
            "uri": "https://tripassist-jeremy.vercel.app" // 👈 請確認這個網址是否正確
          }
        },
        {
          "type": "text",
          "text": "💡 點擊行程項目即可加入日曆",
          "color": "#aaaaaa",
          "size": "xs",
          "align": "center",
          "margin": "md"
        }
      ]
    }
  }
};

// 回傳 (給 Reply API)
return [{
  json: {
    linePayload: {
      "replyToken": replyToken,
      "messages": [ flexMessage ]
    }
  }
}];

// 1. 取得台灣時間的「今天」、「明天(前一天)」與「七天後(七天前)」
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Taipei' }));
now.setHours(0, 0, 0, 0); 

const oneDayLater = new Date(now);
oneDayLater.setDate(now.getDate() + 1); // 這是「倒數 1 天」會觸發的日期 (也就是明天)

const sevenDaysLater = new Date(now);
sevenDaysLater.setDate(now.getDate() + 7); // 這是「倒數 7 天」會觸發的日期 (也就是下週)

// 🛠️ 改良日期解析：確保年份正確
function parseDate(dateStr) {
  if (!dateStr) return null;
  const year = new Date().getFullYear();
  const parts = dateStr.split('/');
  return new Date(year, parseInt(parts[0]) - 1, parseInt(parts[1]), 0, 0, 0);
}

function padZero(str) {
  if (!str) return "";
  return String(str).replace(/\b(\d)\b/g, '0$1');
}

// 📅 動態產生 Google 日曆連結
function makeGCalUrl(title, dateStr, timeStr, type, originalDesc) {
  const year = new Date().getFullYear();
  const parts = (dateStr || '').split('/');
  const m = (parts[0] || '01').padStart(2, '0');
  const d = (parts[1] || '01').padStart(2, '0');

  const tParts = (timeStr || '').split(':');
  const h = (tParts[0] || '00').padStart(2, '0');
  const min = (tParts[1] || '00').padStart(2, '0');

  const start = `${year}${m}${d}T${h}${min}00`;

  let endH = parseInt(h) + 1;
  let endMin = min;
  if (endH >= 24) { endH = 23; endMin = '59'; } 
  const end = `${year}${m}${d}T${String(endH).padStart(2, '0')}${endMin}00`;

  let reminderNote = "";
  if (title.includes('密室') || (type || '').includes('遊戲') || (type || '').includes('娛樂')) {
    reminderNote = "🔔 【系統溫馨提示】：這是密室逃脫行程！儲存前請記得在上方手動新增「1天前」與「7天前」的通知鬧鐘喔！\n\n";
  } else {
    reminderNote = "🔔 【系統溫馨提示】：點擊儲存前，記得確認是否有設定「1天前」的通知鬧鐘喔！\n\n";
  }

  const finalDesc = reminderNote + (originalDesc || '');
  return `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(title)}&dates=${start}/${end}&details=${encodeURIComponent(finalDesc)}&openExternalBrowser=1`;
}

// 2. 抓取資料
const items = [...$input.all()];
const upcomingItems = [];

// 3. 篩選：只抓「剛好明天(距離1天)」與「剛好下週(距離7天)」的行程
for (const item of items) {
  const data = item.json;
  const eventDate = parseDate(data.日期);

  if (eventDate) {
    // 將日期轉為時間戳(毫秒)來做精準比對
    const eventTime = eventDate.getTime();
    const timeOne = oneDayLater.getTime();
    const timeSeven = sevenDaysLater.getTime();

    // 🌟 核心修改：只允許「剛好明天」或「剛好七天後」
    if (eventTime === timeOne || eventTime === timeSeven) {
      upcomingItems.push(data);
    }
  }
}

// 如果沒行程，直接 return 空
if (upcomingItems.length === 0) {
  return []; 
}

// ==========================================
// 🌟 將行程依照「群組ID」進行分類與「訂閱派發」
