// 🛠️ 改良日期解析：確保年份正確
function parseDate(dateStr) {
  if (!dateStr) return null;
  const year = new Date().getFullYear();
  const parts = dateStr.split('/');
  return new Date(year, parseInt(parts[0]) - 1, parseInt(parts[1]), 0, 0, 0);
}

function padZero(str) {
  if (!str) return "";
  return String(str).replace(/\b(\d)\b/g, '0$1');
}

// 📅 動態產生 Google 日曆連結
function makeGCalUrl(title, dateStr, timeStr, type, originalDesc) {
  const year = new Date().getFullYear();
  const parts = (dateStr || '').split('/');
  const m = (parts[0] || '01').padStart(2, '0');
  const d = (parts[1] || '01').padStart(2, '0');

  const tParts = (timeStr || '').split(':');
  const h = (tParts[0] || '00').padStart(2, '0');
  const min = (tParts[1] || '00').padStart(2, '0');

  const start = `${year}${m}${d}T${h}${min}00`;

  let endH = parseInt(h) + 1;
  let endMin = min;
  if (endH >= 24) { endH = 23; endMin = '59'; } 
  const end = `${year}${m}${d}T${String(endH).padStart(2, '0')}${endMin}00`;

  let reminderNote = "";
  if (title.includes('密室') || (type || '').includes('遊戲') || (type || '').includes('娛樂')) {
    reminderNote = "🔔 【系統溫馨提示】：這是密室逃脫行程！儲存前請記得在上方手動新增「1天前」與「7天前」的通知鬧鐘喔！\n\n";
  } else {
    reminderNote = "🔔 【系統溫馨提示】：點擊儲存前，記得確認是否有設定「1天前」的通知鬧鐘喔！\n\n";
  }

  const finalDesc = reminderNote + (originalDesc || '');
  return `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(title)}&dates=${start}/${end}&details=${encodeURIComponent(finalDesc)}&openExternalBrowser=1`;
}

